    constructor() {
        this.label = '';
        this.hint = '';
        this.error = '';
        this.checked = false;
        this.indeterminate = false;
        this.disabled = false;
        this.id = '';
        this.name = '';
        this.value = '';
        this.wrapperClass = '';
        this.checkedChange = new EventEmitter();
        this.autoId = `pf-checkbox-${++nextUid}`;
    }
    get inputId() {
        return this.id || this.autoId;
    }
    get hintId() {
        return this.hint && !this.error ? `${this.inputId}-hint` : null;
    }
    get errorId() {
        return this.error ? `${this.inputId}-error` : null;
    }
    get describedBy() {
        const ids = [this.hintId, this.errorId].filter(Boolean);
        return ids.length ? ids.join(' ') : null;
    }
    get wrapperClasses() {
        return ['ori-choice', this.wrapperClass]
            .filter((c) => Boolean(c))
            .join(' ');
    }
    ngAfterViewInit() {
        this.applyIndeterminate();
    }
    ngOnChanges(changes) {
        if (changes['indeterminate']) {
            this.applyIndeterminate();
        }
    }
