        disabled: [{ type: Input }],
        id: [{ type: Input }],
        name: [{ type: Input }],
        value: [{ type: Input }],
        wrapperClass: [{ type: Input }],
        checkedChange: [{ type: Output }],
        inputEl: [{ type: ViewChild, args: ['inputEl',] }]
    }; }
};
